#!/bin/bash
version=$(bin/neo4j-admin --version | cut -d '.' -f 1)
if [[ $version -ge 5 ]]; then
	bin/neo4j-admin database import full neo4j --delimiter=";" --array-delimiter="|" --quote="'" --overwrite-destination=true --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Microbe-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Microbe-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Nutrient-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Nutrient-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToPhenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToPhenotype-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToGene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToGene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToNutrient-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToNutrient-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/FoodToNutrient-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/FoodToNutrient-part.*" 
else
	bin/neo4j-admin import --database=neo4j --delimiter=";" --array-delimiter="|" --quote="'" --force=true --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Microbe-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Microbe-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Gene-part.*" --nodes="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Nutrient-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/Nutrient-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToPhenotype-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToPhenotype-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToPhenotype-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToGene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToGene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/SnpToGene-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToNutrient-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/MicrobeToNutrient-part.*" --relationships="/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/FoodToNutrient-header.csv,/home/sthoniyot/projects/cardiometabolic-kg/data/processed/biocypher-out/FoodToNutrient-part.*" 
fi